+    if legacy_agent.exists() {
+        return legacy_agent;
+    }
+
+    let legacy_branch = legacy_branch_lease_path(slot_dir, agent, branch);
+    if legacy_branch.exists() {
+        return legacy_branch;
+    }
+
+    if let Some(existing) = existing_agent_lease_path(slot_dir, agent, branch) {
+        return existing;
+    }
+
+    preferred
